import{_ as e,o,c as r,a5 as a}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"PI 电流调节器仿真 -- dq 电流环阶跃响应与带宽参数化","description":"","frontmatter":{"title":"PI 电流调节器仿真 -- dq 电流环阶跃响应与带宽参数化","date":"2026-07-01T00:00:00.000Z","section":"电机控制","chapter":"02-Simulations","category":"电机控制","tags":["imported"],"source":"motor","sourcePath":"frontend/src/components/simulations/CurrentLoopSim.vue","status":"learning","visibility":"public","summary":"Imported from frontend/src/components/simulations/CurrentLoopSim.vue","chapterTitle":"仿真专题","chapterOrder":20},"headers":[],"relativePath":"content/motor/simulations/CurrentLoopSim.md","filePath":"content/motor/simulations/CurrentLoopSim.md","lastUpdated":1782999393000}'),i={name:"content/motor/simulations/CurrentLoopSim.md"};function n(s,t,p,d,m,c){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="pi-电流调节器仿真-dq-电流环阶跃响应与带宽参数化" tabindex="-1">PI 电流调节器仿真 -- dq 电流环阶跃响应与带宽参数化 <a class="header-anchor" href="#pi-电流调节器仿真-dq-电流环阶跃响应与带宽参数化" aria-label="Permalink to &quot;PI 电流调节器仿真 -- dq 电流环阶跃响应与带宽参数化&quot;">​</a></h1><h4 id="pi-电流调节器仿真-dq-电流环阶跃响应与带宽参数化-1" tabindex="-1">PI 电流调节器仿真 -- dq 电流环阶跃响应与带宽参数化 <a class="header-anchor" href="#pi-电流调节器仿真-dq-电流环阶跃响应与带宽参数化-1" aria-label="Permalink to &quot;PI 电流调节器仿真 -- dq 电流环阶跃响应与带宽参数化&quot;">​</a></h4><h2 id="pi-电流调节器带宽参数化原理" tabindex="-1">PI 电流调节器带宽参数化原理 <a class="header-anchor" href="#pi-电流调节器带宽参数化原理" aria-label="Permalink to &quot;PI 电流调节器带宽参数化原理&quot;">​</a></h2><p>**内模原理：**FOC 的 dq 电流环是最内层控制回路，控制带宽设计直接影响转矩响应速度和整个驱动系统的动态性能。电流环的典型设计目标是在保证稳定裕度的前提下尽可能提高带宽。</p><p>**带宽参数化整定法：**将 PI 参数直接与目标带宽 ωbw 关联，是目前工业界最常用的方法：</p><p><strong>Kp = ωbw · L</strong> — 比例增益抵消电感产生的惯性延迟，提供快速的动态响应。</p><p><strong>Ki = ωbw · R</strong> — 积分增益抵消电阻压降引起的稳态误差，消除静差。</p><p>这种方式下闭环传递函数简化为 <em><em>I(s)/I</em>(s) = ωbw/(s + ωbw)</em>*，即一阶低通滤波器，无超调无振荡。电流环带宽一般设为 PWM 频率的 1/20~1/10。</p><p>**dq 解耦：**实际系统中 dq 轴存在交叉耦合（ωe·L·iq 和 ωe·L·id），需加入前馈解耦项使 PI 调节器独立工作。</p>',9)])])}const h=e(i,[["render",n]]);export{u as __pageData,h as default};
